     1→import os from "node:os";
     2→import path from "node:path";
     3→import type { AgentConfig } from "../types.ts";
     4→
     5→export function resolveHome(): string {
     6→  if (process.platform === "win32") {
     7→    return os.homedir();
     8→  }
     9→
    10→  const sudoUser = process.env["SUDO_USER"];
    11→  if (sudoUser) {
    12→    const base = process.platform === "darwin" ? "/Users" : "/home";
    13→    return path.join(base, sudoUser);
    14→  }
    15→
    16→  return os.homedir();
    17→}
    18→
    19→export function getPlatformKey(): "posix" | "windows" {
    20→  return process.platform === "win32" ? "windows" : "posix";
    21→}
    22→
    23→export function getDeployMethod(): "symlink" | "copy" {
    24→  return process.platform === "win32" ? "copy" : "symlink";
    25→}
    26→
    27→export function resolveAgentSkillPath(
    28→  agent: AgentConfig,
    29→  skillName: string,
    30→  home: string
    31→): string {
    32→  const platform = getPlatformKey();
    33→  const template = agent.skills[platform];
    34→  return resolvePlaceholders(template, skillName, home);
    35→}
    36→
    37→export function resolveAgentDetectPath(
    38→  agent: AgentConfig,
    39→  home: string
    40→): string {
    41→  const platform = getPlatformKey();
    42→  const template = agent.detectPaths[platform];
    43→  return resolvePlaceholders(template, "", home);
    44→}
    45→
    46→function resolvePlaceholders(
    47→  template: string,
    48→  skillName: string,
    49→  home: string
    50→): string {
    51→  let result = template.replace("{home}", home);
    52→  result = result.replace("{name}", skillName);
    53→
    54→  if (result.includes("{appdata}")) {
    55→    const appdata = process.env["APPDATA"] ?? path.join(home, "AppData", "Roaming");
    56→    result = result.replace("{appdata}", appdata);
    57→  }
    58→
    59→  return result;
    60→}
