    10→import path from "node:path";
    11→import { AGENT_REGISTRY } from "../config/agents.ts";
    12→import { resolveAgentSkillPath, getDeployMethod } from "./resolve.ts";
    13→import type { AgentId, DeployAction, Manifest } from "../types.ts";
    14→
    15→export function planDeploy(
    16→  manifest: Manifest,
    17→  sourceDir: string,
    18→  detectedAgents: AgentId[],
    19→  home: string
    20→): DeployAction[] {
    21→  const method = getDeployMethod();
    22→  const actions: DeployAction[] = [];
    23→
    24→  for (const skill of manifest.skills) {
    25→    const source = path.resolve(sourceDir, skill.path);
    26→
    27→    for (const agentId of skill.agents) {
    28→      if (!detectedAgents.includes(agentId)) continue;
    29→
    30→      const agent = AGENT_REGISTRY.find((a) => a.id === agentId);
    31→      if (!agent) continue;
    32→
    33→      const target = resolveAgentSkillPath(agent, skill.name, home);
    34→
    35→      actions.push({ skill: skill.name, agent: agentId, source, target, method });
    36→    }
    37→  }
    38→
    39→  return actions;
    40→}
    41→
    42→export function executeDeploy(
    43→  actions: DeployAction[],
    44→  dryRun: boolean,
    45→  verbose: boolean
    46→): { succeeded: number; failed: Array<{ action: DeployAction; error: string }> } {
    47→  let succeeded = 0;
    48→  const failed: Array<{ action: DeployAction; error: string }> = [];
    49→
    50→  for (const action of actions) {
    51→    const label = `${action.skill} -> ${action.agent}`;
    52→
    53→    if (!existsSync(action.source)) {
    54→      const msg = `Source not found: ${action.source}`;
    55→      failed.push({ action, error: msg });
    56→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    57→      continue;
    58→    }
    59→
    60→    if (dryRun) {
    61→      console.log(`  \x1b[36m○\x1b[0m ${label}`);
    62→      if (verbose) {
    63→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    64→      }
    65→      succeeded++;
    66→      continue;
    67→    }
    68→
    69→    try {
    70→      removeExisting(action.target, verbose);
    71→      mkdirSync(path.dirname(action.target), { recursive: true });
    72→
    73→      if (action.method === "symlink") {
    74→        symlinkSync(action.source, action.target, "dir");
    75→      } else {
    76→        cpSync(action.source, action.target, { recursive: true });
    77→      }
    78→
    79→      console.log(`  \x1b[32m✓\x1b[0m ${label}`);
    80→      if (verbose) {
    81→        console.log(`    ${action.method}: ${action.source} -> ${action.target}`);
    82→      }
    83→      succeeded++;
    84→    } catch (err) {
    85→      const msg = err instanceof Error ? err.message : String(err);
    86→      failed.push({ action, error: msg });
    87→      console.error(`  \x1b[31m✗\x1b[0m ${label}: ${msg}`);
    88→    }
    89→  }
    90→
    91→  return { succeeded, failed };
    92→}
    93→
    94→function removeExisting(targetPath: string, verbose: boolean): void {
    95→  if (!existsSync(targetPath) && !isSymlink(targetPath)) return;
    96→
    97→  if (isSymlink(targetPath)) {
    98→    if (verbose) {
    99→      console.log(`    removing existing symlink: ${targetPath}`);
   100→    }
   101→    unlinkSync(targetPath);
   102→  } else {
   103→    if (verbose) {
   104→      console.log(`    \x1b[33m!\x1b[0m replacing existing directory: ${targetPath}`);
   105→    }
   106→    rmSync(targetPath, { recursive: true });
   107→  }
   108→}
   109→
   110→function isSymlink(p: string): boolean {
   111→  try {
   112→    return lstatSync(p).isSymbolicLink();
   113→  } catch {
   114→    return false;
   115→  }
   116→}
